import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import styles from '../css/Cart.module.css';

function Cart() {
    const navigate = useNavigate();
    const [cartItems, setCartItems] = useState([]);

    useEffect(() => {
        loadCart();
    }, []);

    const loadCart = () => {
        const cart = JSON.parse(sessionStorage.getItem('cart') || '[]');
        setCartItems(cart);
    };

    const saveCart = (items) => {
        sessionStorage.setItem('cart', JSON.stringify(items));
        setCartItems(items);
    };

    const updateQuantity = (index, delta) => {
        const updated = [...cartItems];
        updated[index].quantity = Math.max(1, updated[index].quantity + delta);
        saveCart(updated);
    };

    const removeItem = (index) => {
        const updated = cartItems.filter((_, i) => i !== index);
        saveCart(updated);
    };

    const totalPrice = cartItems.reduce((sum, item) => {
        return sum + (item.price * item.quantity);
    }, 0);

    const handleCheckout = () => {
        if (cartItems.length === 0) {
            alert('장바구니가 비어있습니다.');
            return;
        }
        // 장바구니 데이터를 가지고 첫 번째 상품의 구매 페이지로 이동
        const firstItem = cartItems[0];
        navigate(`/gongguapply/${firstItem.title}`, {
            state: { cartItems, totalPrice }
        });
    };

    return (
        <div className={styles.cart}>
            <div className={styles.cartTab}>
                <div className={styles.cartTitle}>장바구니</div>
                <div className={styles.line}></div>
            </div>

            {cartItems.length === 0 ? (
                <div className={styles.cartEmpty}>
                    장바구니가 비어있습니다.
                </div>
            ) : (
                <>
                    <div className={styles.cartList}>
                        {cartItems.map((item, index) => (
                            <div key={index} className={styles.cartItem}>
                                <img
                                    src={item.mainPhoto}
                                    alt={item.title}
                                    className={styles.cartItemImage}
                                />
                                <div className={styles.cartItemInfo}>
                                    <div className={styles.cartItemTitle}>{item.title}</div>
                                    <div className={styles.cartItemPrice}>
                                        {Number(item.price).toLocaleString()}원
                                    </div>
                                    <div className={styles.quantityControl}>
                                        <button
                                            className={styles.quantityBtn}
                                            onClick={() => updateQuantity(index, -1)}
                                        >
                                            -
                                        </button>
                                        <span className={styles.quantityValue}>{item.quantity}</span>
                                        <button
                                            className={styles.quantityBtn}
                                            onClick={() => updateQuantity(index, 1)}
                                        >
                                            +
                                        </button>
                                    </div>
                                </div>
                                <div className={styles.cartItemRight}>
                                    <div className={styles.subtotal}>
                                        {(item.price * item.quantity).toLocaleString()}원
                                    </div>
                                    <button
                                        className={styles.removeBtn}
                                        onClick={() => removeItem(index)}
                                    >
                                        삭제
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className={styles.cartSummary}>
                        <div>
                            <span className={styles.totalLabel}>합계</span>
                        </div>
                        <div>
                            <span className={styles.totalPrice}>
                                {totalPrice.toLocaleString()}원
                            </span>
                            <button
                                className={styles.checkoutBtn}
                                onClick={handleCheckout}
                            >
                                전체 결제하기
                            </button>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

export default Cart;
